// LexFlow — Case Intake Processor
// Normalizes, validates, and prepares payload for the AI pipeline

const item = $input.first().json;
const body = item.body || item;

// ── INPUT VALIDATION ─────────────────────────────────────────
if (!body.case_id || typeof body.case_id !== 'string' || body.case_id.trim() === '') {
  throw new Error('Validation failed: case_id is required and must be a non-empty string');
}

// Validate file sizes (max 10MB per file)
const MAX_FILE_SIZE = 10 * 1024 * 1024;
const attachmentsFull = (body.attachments || []).filter(a => a.data);
for (const file of attachmentsFull) {
  if (file.size && file.size > MAX_FILE_SIZE) {
    throw new Error(`File ${file.name} exceeds 10MB limit (size: ${file.size} bytes)`);
  }
}

// ── NORMALIZE legal_topic ──────────────────────────────────────
// Accept both "Labor Law" (from dashboard) and "Labor" (short form)
const TOPIC_MAP = {
  'labor law':    'Labor Law',
  'labor':        'Labor Law',
  'criminal law': 'Criminal Law',
  'criminal':     'Criminal Law',
  'civil law':    'Civil Law',
  'civil':        'Civil Law',
  'family law':   'Family Law',
  'family':       'Family Law',
  'property law': 'Property Law',
  'property':     'Property Law',
  'corporate law':'Corporate Law',
  'corporate':    'Corporate Law',
  'tax law':      'Tax Law',
  'tax':          'Tax Law',
  'ip':           'IP Law',
  'ip law':       'IP Law',
};
const rawTopic = (body.legal_topic || '').trim();
const normalizedTopic = TOPIC_MAP[rawTopic.toLowerCase()] || rawTopic || 'Other';

// ── NORMALIZE ATTACHMENTS ─────────────────────────────────────
const attachmentsMeta = (body.attachments_meta || body.attachments || [])
  .map(a => ({
    name: a.name || 'unnamed',
    type: a.type || 'application/octet-stream',
    size: a.size || 0,
    ext:  a.ext  || (a.name ? a.name.split('.').pop() : '')
  }));

// ── BUILD CLEAN PAYLOAD ───────────────────────────────────────
const payload = {
  case_id:             body.case_id.trim(),
  timestamp:           body.timestamp || new Date().toISOString(),
  submitted_by:        body.submitted_by || 'Clerk',
  pipeline_status:     'INTAKE_COMPLETE',

  user_name:           body.user_name || '',
  contact_number:      body.contact_number || '',
  date_of_birth:       body.date_of_birth || '',
  civil_status:        body.civil_status || '',
  address:             body.address || '',
  occupation:          body.occupation || '',

  legal_topic:         normalizedTopic,
  legal_issue:         body.legal_issue || '',
  incident_date:       body.incident_date || '',
  opposing_party:      body.opposing_party || '',
  urgency:             body.urgency || 'MEDIUM',

  legal_narrative:     body.legal_narrative || '',
  clerk_notes:         body.clerk_notes || '',

  documents_submitted: body.documents_submitted || [],
  attachments_meta:    attachmentsMeta,
  document_urls:       [],

  lawyer_a:            null,
  lawyer_b:            null,
  senior_partner:      null
};

return [{ json: { ...payload, _attachments_full: attachmentsFull } }];

// Upload files to Supabase Storage
const item = $input.first().json;
const caseId = item.case_id;
const attachments = item._attachments_full || [];

if (!attachments || attachments.length === 0) {
  return [{ json: { ...item, document_urls: [], upload_errors: null, _attachments_full: undefined } }];
}

const supabaseUrl = "https://ncvlpqbevllqwrpdauxi.supabase.co";
const supabaseKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im5jdmxwcWJldmxscXdycGRhdXhpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjE1NTk2NiwiZXhwIjoyMDg3NzMxOTY2fQ.Cs5k-uKtxyiTejLzsrpJllPg3-cZ6qvFDSjEdEVnBMU";
const bucket = "case_files";

// Retry wrapper
async function fetchWithRetry(url, options, maxRetries = 3, delayMs = 2000) {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (!res.ok) throw new Error(`HTTP ${res.status}: ${await res.text()}`);
      return res;
    } catch (err) {
      if (attempt === maxRetries) throw err;
      await new Promise(r => setTimeout(r, delayMs * attempt));
    }
  }
}

const MIME_TYPES = {
  'pdf':  'application/pdf',
  'jpg':  'image/jpeg',
  'jpeg': 'image/jpeg',
  'png':  'image/png',
  'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'doc':  'application/msword',
  'xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  'txt':  'text/plain'
};

const uploadedUrls = [];
const errors = [];

for (const file of attachments) {
  const originalName = file.name || 'document';
  const ext = originalName.split('.').pop().toLowerCase();
  const mimeType = MIME_TYPES[ext] || 'application/octet-stream';
  const timestamp = Date.now();
  const random = Math.random().toString(36).substring(2, 8);
  const fileName = `${timestamp}_${random}_${originalName}`;
  const filePath = `${caseId}/${fileName}`;

  try {
    const binaryStr = atob(file.data);
    const bytes = new Uint8Array(binaryStr.length);
    for (let i = 0; i < binaryStr.length; i++) {
      bytes[i] = binaryStr.charCodeAt(i);
    }

    await fetchWithRetry(
      `${supabaseUrl}/storage/v1/object/${bucket}/${filePath}`,
      {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${supabaseKey}`,
          'Content-Type': mimeType,
          'x-upsert': 'true'
        },
        body: bytes
      }
    );

    const publicUrl = `${supabaseUrl}/storage/v1/object/public/${bucket}/${filePath}`;
    uploadedUrls.push({ name: originalName, url: publicUrl, type: mimeType });
  } catch (error) {
    console.error(`Upload failed for ${originalName}:`, error.message);
    errors.push({ name: originalName, error: error.message });
  }
}

// Patch cases row with document_urls if any succeeded
if (uploadedUrls.length > 0) {
  try {
    await fetchWithRetry(
      `${supabaseUrl}/rest/v1/cases?case_id=eq.${caseId}`,
      {
        method: 'PATCH',
        headers: {
          'Authorization': `Bearer ${supabaseKey}`,
          'apikey': supabaseKey,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: JSON.stringify({ document_urls: uploadedUrls })
      }
    );
  } catch (patchError) {
    console.error('Failed to patch case with document_urls:', patchError.message);
    errors.push({ name: 'PATCH_CASE', error: patchError.message });
  }
}

const result = {
  ...item,
  document_urls: uploadedUrls,
  upload_errors: errors.length > 0 ? errors : null,
  _attachments_full: undefined
};

return [{ json: result }];
